+/* ── react-tweet: Glassmorphic Frankenstein Overrides ───────────────── */
+
+/* Core theme variables — transparent glass background, green accents */
+.tweet-embed-wrapper [data-theme="dark"] .react-tweet-theme {
+  --tweet-bg-color: transparent !important;
+  --tweet-bg-color-hover: rgba(34, 197, 94, 0.03) !important;
+  --tweet-border: none !important;
+  --tweet-container-margin: 0 !important;
+  --tweet-font-color: #e2e8f0 !important;
+  --tweet-font-color-secondary: #64748b !important;
+  --tweet-color-blue-primary: #22c55e !important;
+  --tweet-color-blue-primary-hover: #16a34a !important;
+  --tweet-color-blue-secondary: #4ade80 !important;
+  --tweet-color-blue-secondary-hover: rgba(74, 222, 128, 0.1) !important;
+  --tweet-color-green-primary: #22c55e !important;
+  --tweet-color-green-primary-hover: rgba(34, 197, 94, 0.1) !important;
+  --tweet-color-red-primary: #f87171 !important;
+  --tweet-color-red-primary-hover: rgba(248, 113, 113, 0.1) !important;
+  --tweet-twitter-icon-color: #4ade80 !important;
+  --tweet-verified-blue-color: #4ade80 !important;
+  --tweet-quoted-bg-color-hover: rgba(34, 197, 94, 0.05) !important;
+}
+
+.tweet-wall-grid .tweet-embed-wrapper {
+  min-width: 0;
+}
+
+/* Fill grid cell */
+.tweet-embed-wrapper [data-theme="dark"] > div {
+  height: 100%;
+}
+
+/* Transparent rounded container */
+.tweet-embed-wrapper .react-tweet-theme {
+  border-radius: 0 !important;
+  border: none !important;
+  overflow: hidden;
+  background: transparent !important;
+}
+
+/* Media images — green glow treatment (excludes profile avatars) */
+.tweet-embed-wrapper .react-tweet-theme [data-testid="tweetPhoto"] img,
+.tweet-embed-wrapper .react-tweet-theme [class*="mediaWrapper"] img,
+.tweet-embed-wrapper .react-tweet-theme [class*="media"] img:not([class*="avatar"]) {
+  border-radius: 0.75rem !important;
+  border: 1px solid rgba(34, 197, 94, 0.1) !important;
+  transition: border-color 0.4s, box-shadow 0.4s;
+}
+
+.franken-tweet-card:hover .react-tweet-theme [data-testid="tweetPhoto"] img,
+.franken-tweet-card:hover .react-tweet-theme [class*="mediaWrapper"] img,
+.franken-tweet-card:hover .react-tweet-theme [class*="media"] img:not([class*="avatar"]) {
+  border-color: rgba(34, 197, 94, 0.25) !important;
+  box-shadow: 0 0 20px rgba(34, 197, 94, 0.1);
+}
+
+/* Links in tweet body — green instead of blue */
+.tweet-embed-wrapper .react-tweet-theme a {
+  color: #4ade80 !important;
+  transition: color 0.2s;
+}
+
+.tweet-embed-wrapper .react-tweet-theme a:hover {
+  color: #86efac !important;
+}
+
+/* Info bar / date — monospace */
+.tweet-embed-wrapper .react-tweet-theme time {
+  font-family: var(--font-mono) !important;
+  font-size: 0.7rem !important;
+  color: #475569 !important;
+}
+
+/* Quoted tweet borders — green tint */
+.tweet-embed-wrapper .react-tweet-theme [class*="quoted"] {
+  border-color: rgba(34, 197, 94, 0.15) !important;
+  border-radius: 0.75rem !important;
+}
+
+/* Action bar (like/reply/retweet row) — subtle */
+.tweet-embed-wrapper .react-tweet-theme [class*="actions"] {
+  border-top-color: rgba(34, 197, 94, 0.08) !important;
+  opacity: 0.7;
+  transition: opacity 0.3s;
+}
+
+.franken-tweet-card:hover .react-tweet-theme [class*="actions"] {
+  opacity: 1;
 }
